Il seguente frammento di codice Python definisce una classe Node per rappresentare un nodo in una lista collegata e una funzione process_list. Cosa fa specificatamente?

```python
class Node:
    def __init__(self, data=None):
        self.data = data
        self.next = None

def process_list(head, a, b):
    current = head
    while current:
        if current.data == a:
            current.data = b
            return True
        current = current.next
    return False
```

Il seguente frammento di codice in C definisce una struttura per una lista collegata e una funzione performOperation. Cosa fa specificamente la funzione performOperation?

```c
typedef struct Node {
    int data;
    struct Node* next;
} Node;

void performOperation(Node** head_ref, int new_data) {
    Node* new_node = (Node*)malloc(sizeof(Node));
    new_node->data = new_data;
    new_node->next = NULL;
    if (*head_ref == NULL) {
        *head_ref = new_node;
        return;
    }
    Node* last = *head_ref;
    while (last->next != NULL)
        last = last->next;
    last->next = new_node;
}
```

Che tipo di algoritmo di ricerca rappresenta la seguente funzione?

```c
int binary_search_iter(int a[], int n, int valore) {
    int sx = 0, dx = n - 1;
    while (sx <= dx) {
        int mx = sx + (dx - sx) / 2;
        if (a[mx] == valore) return mx;
        if (a[mx] < valore) sx = mx + 1;
        else dx = mx - 1;
    }
    return -1;
}
```

